import React from "react";
import { Link } from "react-router-dom"; // ✅ reativado para o botão de detalhes

export default function CardEvento({ evento, onRemover, onEditar }) {
  // ✅ Badge de status (aberto/lotado) — compatível com snake_case do banco
  const vagas = evento.vagas_restantes ?? evento.vagasRestantes;
  const temVagas = typeof vagas === "number";
  const lotado = temVagas && vagas === 0;

  return (
    <article className="card">
      <div>
        <h3>{evento.titulo}</h3>

        {temVagas && (
          <span className={lotado ? "badge lotado" : "badge aberto"}>
            {lotado ? "LOTADO" : "ABERTO"}
          </span>
        )}

        <p className="muted">
          {evento.data} • {evento.local}
        </p>

        {evento.descricao && (
          <p className="descricao">{evento.descricao}</p>
        )}
      </div>

      <div className="stack">
        {/* ✅ ADICIONADO: botão de detalhes */}
        <Link className="btn" to={`/evento/${evento.id}`}>
          Ver detalhes
        </Link>

        <button className="btn danger" onClick={() => onRemover(evento.id)}>
          Remover
        </button>
      </div>
    </article>
  );
}
